import React from 'react';
import { useOrderContext } from '../contextAPI/OrderCartContext';
import CartItemCard from './Card';
import '../style/CartPage.css';

const CartPage = () => {
  const { order } = useOrderContext();

  const totalCartAmount = Object.values(order).reduce((total, item) => {
    return total + (item.price * item.quantity);
  }, 0);

  return (
    <div className="cart-page">
      <h2>Your Cart</h2>
      <div className="cart-items">
        {Object.keys(order).length === 0 ? (
          <p>Your cart is empty</p>
        ) : (
          Object.entries(order).map(([productName, itemDetails]) => (
            <CartItemCard
              key={productName}
              name={productName}
              description={itemDetails.description}
              price={itemDetails.price}
              quantity={itemDetails.quantity}
            />
          ))
        )}
      </div>
      <div className="cart-summary">
        <p>Total Amount: ${totalCartAmount.toFixed(2)}</p>
        <button 
          onClick={() => alert("Proceeding to Payment...")} 
          className="checkout-button"
          disabled={Object.keys(order).length === 0}
        >
          Proceed to Payment
        </button>
      </div>
    </div>
  );
};

export default CartPage;
